/**
 * n8n Function Node - Transform Invoice Detail JSON for SQLite Insert
 * Handles the nested webhook structure from ActiveReports
 */

// Get the webhook data - it's nested in body
const inputData = $input.all()[0].json;

// Try to access the data - it might be in different locations
let webhookData;

if (inputData.body) {
    webhookData = inputData.body;
} else if (inputData.reportType) {
    webhookData = inputData;
} else {
    throw new Error('Could not find webhook data. Structure: ' + JSON.stringify(Object.keys(inputData)));
}

// Validate we have the items array
if (!webhookData.items || !Array.isArray(webhookData.items)) {
    throw new Error('Items array not found. Available keys: ' + JSON.stringify(Object.keys(webhookData)));
}

const { reportType, generatedAt, totalItems, items } = webhookData;

/**
 * Parse date from MM/DD/YYYY HH:MM:SS to ISO format
 */
function parseDate(dateString) {
    if (!dateString) return null;

    try {
        const [datePart, timePart] = dateString.split(' ');
        const [month, day, year] = datePart.split('/');
        const [hours, minutes, seconds] = (timePart || '00:00:00').split(':');

        const date = new Date(year, month - 1, day, hours, minutes, seconds);
        return date.toISOString();
    } catch (error) {
        console.error('Error parsing date:', dateString, error);
        return null;
    }
}

/**
 * Group items by invoice number
 */
function groupItemsByInvoice(items) {
    const grouped = {};

    items.forEach(item => {
        const invoiceNumber = item.InvoiceNumber;

        if (!grouped[invoiceNumber]) {
            grouped[invoiceNumber] = {
                InvoiceNumber: item.InvoiceNumber,
                InvoiceDate: item.InvoiceDate,
                InvoiceDetailID: item.InvoiceDetailID, // kept for reference only -- NOT used as InvoiceID (see buildInvoiceId)
                SupplierName: item.SupplierName,
                StatusChangedOn: item.StatusChangedOn,
                LocationPrintName: item.LocationPrintName,
                items: []
            };
        }

        grouped[invoiceNumber].items.push(item);
    });

    return grouped;
}

/**
 * Build a stable, deterministic InvoiceID for the upsert match key.
 * IMPORTANT: do NOT use a per-line-item ID (e.g. InvoiceDetailID) here --
 * this report re-sends the same invoice on every scheduled run, and if the
 * "first" item in the group differs between runs, a per-item ID produces a
 * *different* value each time, so the upsert can't find the existing row
 * and inserts a duplicate instead of updating it. InvoiceNumber+SupplierName
 * is stable across every re-send of the same real invoice.
 */
function buildInvoiceId(invoiceNumber, supplierName) {
    const number = String(invoiceNumber ?? '').trim();
    const supplier = String(supplierName ?? '').trim().toUpperCase();
    return supplier ? `${number}::${supplier}` : number;
}

// Group the items by invoice
const invoiceGroups = groupItemsByInvoice(items);

// Transform each invoice group into database records
const records = [];

for (const [invoiceNumber, invoiceData] of Object.entries(invoiceGroups)) {
    const {
        InvoiceNumber,
        InvoiceDate,
        InvoiceDetailID,
        SupplierName,
        StatusChangedOn,
        items: invoiceItems
    } = invoiceData;

    records.push({
        InvoiceID: buildInvoiceId(InvoiceNumber, SupplierName),
        InvoiceDate: parseDate(InvoiceDate),
        InvoiceNumber: InvoiceNumber,
        SupplierName: SupplierName,
        StatusChangedOn: parseDate(StatusChangedOn),
        LocationID: null,
        TotalItems: invoiceItems.length,
        ItemDetails: JSON.stringify(invoiceItems),
        LastProcessedAt: new Date().toISOString(),
        CreatedAt: new Date().toISOString(),
        ModifiedAt: new Date().toISOString()
    });
}

// Return the transformed records for n8n to insert
return records.map(record => ({ json: record }));
